def generate():
    path = CACHE / "synthetic_code_reasoning.pkl"
    texts = []
    for s in SAMPLES:
        t = f"<|user|>\n{s['problem']}\n<|reasoning|>\n{s['reasoning']}\n<|assistant|>\n{s['code']}\n<|end|>"
        texts.append(t)
    pickle.dump(texts, open(path, "wb"))
    print(f"Generated {len(texts)} synthetic code+reasoning samples -> {path}")


